import os
import shlex
import subprocess
import tempfile
from urllib.parse import urlparse

from google.cloud import storage


def _parse_gs_uri(uri: str):
    parsed = urlparse(uri)
    if parsed.scheme != "gs" or not parsed.netloc:
        raise ValueError("Invalid gs:// URI")
    return parsed.netloc, parsed.path.lstrip("/")


def image_convert(event, context):
    bucket_name = event["bucket"]
    object_name = event["name"]
    metadata = event.get("metadata") or {}

    source_name = metadata.get("source") or object_name
    output_name = metadata.get("output") or f"converted-{os.path.basename(source_name)}"
    options = metadata.get("options", "")

    client = storage.Client()
    bucket = client.bucket(bucket_name)

    source_blob = bucket.blob(source_name)
    if not source_blob.exists():
        raise FileNotFoundError(f"Source object not found: gs://{bucket_name}/{source_name}")

    with tempfile.TemporaryDirectory() as tmpdir:
        input_path = os.path.join(tmpdir, os.path.basename(source_name))
        output_path = os.path.join(tmpdir, os.path.basename(output_name))

        source_blob.download_to_filename(input_path)

        cmd = ["convert", input_path] + shlex.split(options) + [output_path]
        result = subprocess.call(cmd)
        if result != 0:
            raise RuntimeError(f"convert failed with exit code {result}")

        if output_name.startswith("gs://"):
            out_bucket_name, out_object_name = _parse_gs_uri(output_name)
            out_bucket = client.bucket(out_bucket_name)
            out_blob = out_bucket.blob(out_object_name)
        else:
            out_blob = bucket.blob(output_name)

        out_blob.upload_from_filename(output_path)

    return "OK"